private static function retrieveClosurePattern($pure, $closureName)
{
    $pattern = '/';
    if (!$pure) {
        $pattern .= preg_quote(self::$registeredDelimiters[0]) . "\s*";
    }
    $pattern .= "$closureName\(([a-z0-9,\.\s]+)\)";
    if (!$pure) {
        $pattern .= "\s*" . preg_quote(self::$registeredDelimiters[1]);
    }
    return $pattern . "/i";
}

